:Emission  rdf:type          owl:Class ;
        rdfs:comment         "An emission is a specific result that relates to the release or discharge of substances at emission points."@en ;
        rdfs:label           "Emission"@en ;
        rdfs:subClassOf      sosa:Result ;
        rdfs:subClassOf      [ rdf:type            owl:Restriction ;
                               owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
