:Process  rdf:type           owl:Class ;
        rdf:subClassOf       [ rdf:type            owl:Restriction ;
                               owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                               owl:onProperty      pplan:hasStep ;
                               owl:someValuesFrom  :Process
                             ] ;
        rdfs:comment         "An (environmental) process is an industrial process to be filled in by the user at a specific location consisting of multiple procedure steps that describe the process. A process can be hierarchically structured as a plan with substeps."@en ;
        rdfs:label           "Process"@en ;
        rdfs:subClassOf      sosa:Procedure , pplan:Plan , pplan:Step ;
        rdfs:subClassOf      [ rdf:type            owl:Restriction ;
                               rdfs:comment        "A process can be derived from a (generic) procedure (optional). Max 1 because a process can only be derived from 1 procedure and this procedure would need to be a collection of other procedures."@en ;
                               owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                               owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                               owl:onProperty      dc:type ;
                               owl:someValuesFrom  sosa:Procedure
                             ] ;
        rdfs:subClassOf      [ rdf:type            owl:Restriction ;
                               owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                               owl:onProperty      ssn:implementedBy ;
                               owl:someValuesFrom  :Installation
                             ] ;
        rdfs:subClassOf      [ rdf:type            owl:Restriction ;
                               rdfs:comment        "A process can have a validity start"@en ;
                               owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                               owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                               owl:onProperty      dc:issued ;
                               owl:someValuesFrom  xsd:date
                             ] ;
        rdfs:subClassOf      [ rdf:type            owl:Restriction ;
                               rdfs:comment        "A process can be part of one or more other processes"@en ;
                               owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                               owl:onProperty      pplan:isStepOfPlan ;
                               owl:someValuesFrom  :Process
                             ] ;
        rdfs:subClassOf      [ rdf:type            owl:Restriction ;
                               rdfs:comment        "A process must have a single status"@en ;
                               owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                               owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                               owl:onProperty      adms:status ;
                               owl:someValuesFrom  adms:Status
                             ] ;
        rdfs:subClassOf      [ rdf:type            owl:Restriction ;
                               rdfs:comment        "A process can have a validity end"@en ;
                               owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                               owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                               owl:onProperty      dc:valid ;
                               owl:someValuesFrom  xsd:date
                             ] ;
        rdfs:subClassOf      [ rdf:type            owl:Restriction ;
                               rdfs:comment        "A process can have multiple sections"@en ;
                               owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                               owl:onProperty      :section ;
                               owl:someValuesFrom  :Section
                             ] ;
        rdfs:subClassOf      [ rdf:type            owl:Restriction ;
                               rdfs:comment        "A process can optionally use a variable that represents a system"@en ;
                               owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                               owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                               owl:onProperty      ssn:implementedBy ;
                               owl:someValuesFrom  ssn:System
                             ] ;
        rdfs:subClassOf      [ rdf:type            owl:Restriction ;
                               rdfs:comment        "A process can have at least one output variable (substance)"@en ;
                               owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                               owl:onProperty      pplan:hasOutputVar ;
                               owl:someValuesFrom  pplan:Variable
                             ] ;
        rdfs:subClassOf      [ rdf:type            owl:Restriction ;
                               rdfs:comment        "A process must have a creation date"@en ;
                               owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                               owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                               owl:onProperty      dc:created ;
                               owl:someValuesFrom  xsd:dateTime
                             ] ;
        rdfs:subClassOf      [ rdf:type            owl:Restriction ;
                               rdfs:comment        "A process must have a modification date"@en ;
                               owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                               owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                               owl:onProperty      dc:modified ;
                               owl:someValuesFrom  xsd:dateTime
                             ] ;
        rdfs:subClassOf      [ rdf:type            owl:Restriction ;
                               rdfs:comment        "A process can have at least one input variable (substance)"@en ;
                               owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                               owl:onProperty      pplan:hasInputVar ;
                               owl:someValuesFrom  pplan:Variable
                             ] ;
        rdfs:subClassOf      [ rdf:type            owl:Restriction ;
                               rdfs:comment        "A process must have a label"@en ;
                               owl:minCardinality  "1"^^xsd:nonNegativeInteger ;
                               owl:onProperty      rdfs:label
                             ] ;
        rdfs:subClassOf      [ rdf:type            owl:Restriction ;
                               rdfs:comment        "A process can be a revision of another process (optional)"@en ;
                               owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                               owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                               owl:onProperty      prov:wasRevisionOf ;
                               owl:someValuesFrom  :Process
                             ] ;
        owl:equivalentClass  [ rdf:type      owl:Class ;
                               rdfs:comment  "Process can be a plan on its own (multi step)"@en ;
                               owl:unionOf   ( pplan:Step pplan:MultiStep pplan:Plan )
