                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      foaf:phone
                         ] ;
        rdfs:subClassOf  [ rdf:type            owl:Restriction ;
                           rdfs:comment        "An operator contact person must have a role within the organization"@en ;
                           owl:maxCardinality  "1"^^xsd:nonNegativeInteger ;
                           owl:minCardinality  "0"^^xsd:nonNegativeInteger ;
                           owl:onProperty      org:hasRole
                         ] ;
        hydra:search     [ rdf:type        hydra:IriTemplate ;
                           hydra:mapping   [ hydra:property  dc:created ;
